// Keep only the best talent pools and prepare a clean context for prospect-query generation.
// This node is intentionally deterministic so the demo remains stable.
const rows = items.map(i => i.json);

const selected = rows
  .filter(r => {
    const score = Number(r.global_priority_score || r.Global_priority_score || 0);
    const priority = String(r.priority || '').toLowerCase();
    return priority.includes('act now') || score >= 70;
  })
  .sort((a, b) => Number(b.global_priority_score || 0) - Number(a.global_priority_score || 0))
  .slice(0, 6);

// Fallback: if no row matches because scores are strings/missing, keep top 5 rows.
const finalRows = selected.length ? selected : rows.slice(0, 5);

return finalRows.map((r, index) => ({
  json: {
    watchlist_batch_id: `watch_batch_${new Date().toISOString().slice(0,10)}`,
    query_id: r.query_id || 'q_001',
    source_company: r.company || r.source_company || 'Unknown',
    target_role: 'Senior AI Engineer',
    geo: 'France',
    global_priority_score: r.global_priority_score || '',
    priority: r.priority || 'Watch',
    likely_teams: r.likely_teams || '',
    why_it_matters: r.why_it_matters || '',
    recommended_sourcing_action: r.recommended_sourcing_action || '',
    best_outreach_narrative: r.best_outreach_narrative || '',
    row_number: index + 1
  }
}));

