return items.flatMap((item, itemIndex) => {
  const base = $items('Keep High Priority Pools')[itemIndex]?.json || {};
  let raw =
    item.json.choices?.[0]?.message?.content ||
    item.json.message?.content ||
    item.json.output_text ||
    item.json.text ||
    '';

  raw = raw.replace(/```json/g, '').replace(/```/g, '').trim();

  let parsed;
  try {
    parsed = JSON.parse(raw);
  } catch (e) {
    // Fallback so the demo never breaks if OpenAI returns malformed JSON.
    const company = base.source_company || 'Unknown';
    parsed = {
      source_company: company,
      target_role: base.target_role || 'Senior AI Engineer',
      prospect_strategy: `Search for under-visible AI/ML profiles in ${company} using manual recruiter validation.`,
      queries: [
        {
          source_type: 'LinkedIn Manual Search',
          search_query: `site:linkedin.com/in "${company}" "Machine Learning Engineer" "Paris"`,
          expected_profile_type: 'ML / AI engineer with possible latent seniority',
          priority: 'High',
          reason_to_search: `${company} was ranked as a relevant talent pool for Mirakl.`,
          suggested_filters: 'France; Paris; 3+ years tenure; AI/ML/Data/Platform keywords'
        },
        {
          source_type: 'Google Search',
          search_query: `"${company}" "AI Engineer" "France"`,
          expected_profile_type: 'AI engineer or applied ML profile',
          priority: 'Medium',
          reason_to_search: 'Find public references outside LinkedIn.',
          suggested_filters: 'France; AI; LLM; RAG; platform'
        }
      ]
    };
  }

  const queries = Array.isArray(parsed.queries) ? parsed.queries : [];

  return queries.map((q, index) => ({
    json: {
      prospect_id: `prospect_${Date.now()}_${itemIndex}_${index}`,
      query_id: base.query_id || 'q_001',
      source_company: parsed.source_company || base.source_company || '',
      target_role: parsed.target_role || base.target_role || 'Senior AI Engineer',
      search_query: q.search_query || '',
      source_type: q.source_type || 'Google Search',
      generated_from_signal: parsed.prospect_strategy || base.why_it_matters || '',
      priority: q.priority || 'Medium',
      reason_to_search: q.reason_to_search || '',
      expected_profile_type: q.expected_profile_type || '',
      suggested_filters: q.suggested_filters || '',
      status: 'To search',
      created_at: new Date().toISOString().slice(0, 10)
    }
  }));
});
